#include <stdio.h>
#include <math.h>

int main() {
    int n;
    double sum = 0.0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        double term = numerator / denominator;

        if (i % 2 != 0) {
            sum += term;
        } else {
            sum -= term;
        }
    }

    printf("The sum of the series is: %.6f\n", sum);

    return 0;
}

#include <stdio.h>

int main() {
    int n;

    // Read integer n from user
    printf("Enter an integer n (1 to 10): ");
    scanf("%d", &n);

    // Validate input
    if (n < 1 || n > 10) {
        printf("Invalid input. Please enter a number between 1 and 10.\n");
        return 1;
    }

    // Generate expanding triangle pattern
    for (int i = 1; i <= n; i++) {
        // Print leading spaces
        for (int j = n - i; j > 0; j--) {
            printf(" ");
        }

        // Print digits
        for (int k = 0; k < i; k++) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <math.h>

// Function to calculate the distance between two points
double distance(double x1, double y1, double x2, double y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

// Function to check if three points are collinear
int isCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
}

// Function to calculate the area of a triangle using Heron's formula
double heronsFormula(double side1, double side2, double side3) {
    double s = (side1 + side2 + side3) / 2.0;
    return sqrt(s * (s - side1) * (s - side2) * (s - side3));
}

int main() {
    // Read coordinates of 4 points
    double x[4], y[4];
    printf("Enter the coordinates of 4 points: ");
    for (int i = 0; i < 4; i++) {
        scanf("%lf %lf", &x[i], &y[i]);
    }

    // Generate all 3-point combinations
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                double side1 = distance(x[i], y[i], x[j], y[j]);
                double side2 = distance(x[j], y[j], x[k], y[k]);
                double side3 = distance(x[k], y[k], x[i], y[i]);

                // Check if points are collinear
                if (isCollinear(x[i], y[i], x[j], y[j], x[k], y[k])) {
                    printf("Collinear: %lf, %lf, %lf\n", x[i], y[i], x[j]);
                    continue;
                }

                // Calculate area using Heron's formula
                double area = heronsFormula(side1, side2, side3);
                printf("Area of triangle (%.3lf, %.3lf), (%.3lf, %.3lf), (%.3lf, %.3lf): %.3lf\n", 
                       x[i], y[i], x[j], y[j], x[k], y[k], area);
            }
        }
    }

    return 0;
}
